#include <iostream>

bool isLeapYear(int year) {
    return (year % 4 == 0) && ((year % 100 != 0) || (year % 400 == 0));
}

int main() {
    int year;
    std::cin >> year;
    std::cout << (isLeapYear(year) ? "leap year" : "not a leap year") << "\n";
    return 0;
}
